CREATE TYPE dicom_report_type AS ENUM ('SC', 'SR', 'GSPS', 'ENCAPSULATED_PDF');
CREATE TYPE severity AS ENUM ('NORMAL', 'SUSPECT', 'ABNORMAL');

CREATE TABLE aet (
    id SERIAL PRIMARY KEY,
    name VARCHAR(25) NOT NULL
);

CREATE TABLE study (
    id SERIAL PRIMARY KEY,
    study_instance_uid VARCHAR(255) NOT NULL,
    aet_id INTEGER NOT NULL REFERENCES aet(id)
);

CREATE TABLE series (
    id SERIAL PRIMARY KEY,
    series_instance_uid VARCHAR(255) NOT NULL,
    study_id INTEGER NOT NULL REFERENCES study(id)
);

CREATE TABLE dicom (
    id SERIAL PRIMARY KEY,
    sop_instance_uid VARCHAR(255) NOT NULL,
    container_name VARCHAR(50) NOT NULL,
    file_name VARCHAR(255) NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    series_id INTEGER NOT NULL REFERENCES series(id)
);

CREATE TABLE prediction (
    id SERIAL PRIMARY KEY,
    label VARCHAR(20) NOT NULL,
    severity severity NOT NULL,
    dicom_id INTEGER NOT NULL REFERENCES dicom(id)
);

CREATE TABLE dicom_report (
    id SERIAL PRIMARY KEY,
    type dicom_report_type NOT NULL,
    container_name VARCHAR(50) NOT NULL,
    file_name VARCHAR(255) NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    dicom_id INTEGER NOT NULL REFERENCES dicom(id)
);


















